package com.google.gson.internal.bind;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.io.IOException;
import java.lang.reflect.Method;
import static org.junit.jupiter.api.Assertions.*;

class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  void setUp() throws Exception {
    // Create a JsonPrimitive boolean true element to initialize the reader
    JsonPrimitive booleanTrue = new JsonPrimitive(true);
    reader = new JsonTreeReader(booleanTrue);

    // Using reflection to set stack and stackSize for controlled test environment
    // stack will contain a JsonPrimitive boolean
    var stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = booleanTrue;
    stackField.set(reader, stackArray);

    var stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    var pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndices[0] = 0;
    pathIndicesField.set(reader, pathIndices);
  }

  @Test
  void nextBoolean_returnsTrueAndIncrementsPathIndex() throws Exception {
    boolean result = reader.nextBoolean();
    assertTrue(result);

    var pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(reader);
    assertEquals(1, pathIndices[0]);
  }

  @Test
  void nextBoolean_stackSizeZero_noPathIndexIncrement() throws Exception {
    // Set stackSize to 0 to test no increment of pathIndices
    var stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 0);

    // Push a boolean JsonPrimitive onto stack manually to avoid errors in popStack()
    var stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = new JsonPrimitive(false);
    stackField.set(reader, stackArray);

    // Call nextBoolean and verify no exception and correct return
    // But expect(JsonToken.BOOLEAN) will fail because stack is empty logically
    // So we need to mock expect to do nothing or call private method expect reflectively to test nextBoolean

    // Use reflection to replace expect method with a no-op for this test
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);

    // Because expect throws IOException if token mismatches, we must set stack so peekStack returns BOOLEAN
    // We simulate peekStack by pushing a JsonPrimitive boolean on stack

    // Actually, the real nextBoolean() calls expect and popStack. We already have stack with one boolean at index 0.
    // Let's set stackSize to 1 and then to 0 after expect call to simulate stackSize zero after popping

    // So first set stackSize to 1
    stackSizeField.setInt(reader, 1);

    boolean result = reader.nextBoolean();
    assertTrue(result);

    // Now stackSize should be 0 after popStack, so pathIndices not incremented
    int[] pathIndices = (int[]) reader.getClass().getDeclaredField("pathIndices").get(reader);
    assertEquals(0, pathIndices[0]);
  }

  @Test
  void nextBoolean_expectThrowsIOException() throws Exception {
    // Create a reader with a non-boolean JsonPrimitive to cause expect to fail
    JsonPrimitive nonBoolean = new JsonPrimitive("notABoolean");
    JsonTreeReader badReader = new JsonTreeReader(nonBoolean);

    var stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = nonBoolean;
    stackField.set(badReader, stackArray);

    var stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(badReader, 1);

    assertThrows(IOException.class, badReader::nextBoolean);
  }
}
